    /**
     * Get platform color.
     */
    public static function get_platform_color( $platform ) {
        $all = array_merge(
            self::get_social_platforms(),
            self::get_streaming_platforms()
        );
        return isset( $all[ $platform ] ) ? $all[ $platform ]['color'] : '#6C3AE8';
    }

    /**
     * Get platform label.
     */
    public static function get_platform_label( $platform ) {
        $all = array_merge(
            self::get_social_platforms(),
            self::get_streaming_platforms()
        );
        return isset( $all[ $platform ] ) ? $all[ $platform ]['label'] : ucfirst( $platform );
    }

    /**
     * Sanitize a section array coming from POST.
     */
    public static function sanitize_sections( $raw ) {
        if ( ! is_array( $raw ) ) return array();
        $clean = array();
        foreach ( $raw as $section ) {
            $type = sanitize_key( $section['type'] ?? 'custom' );
            $s = array(
                'id'         => sanitize_key( $section['id'] ?? 'sec_' . wp_generate_uuid4() ),
                'type'       => $type,
                'title'      => sanitize_text_field( $section['title'] ?? '' ),
                'active'     => ! empty( $section['active'] ),
                'expandable' => ! empty( $section['expandable'] ),
                'display'    => sanitize_key( $section['display'] ?? 'buttons' ),
                'links'      => array(),
            );
            if ( $type === 'release' ) {
                $s['cover_image_url'] = esc_url_raw( $section['cover_image_url'] ?? '' );
                $s['cover_image_id']  = absint( $section['cover_image_id'] ?? 0 );
                $s['description']     = sanitize_textarea_field( $section['description'] ?? '' );
                $s['release_date']    = sanitize_text_field( $section['release_date'] ?? '' );
            }
            if ( $type === 'custom' ) {
                $s['url']  = esc_url_raw( $section['url'] ?? '' );
                $s['icon'] = sanitize_key( $section['icon'] ?? 'link' );
            }
            if ( isset( $section['links'] ) && is_array( $section['links'] ) ) {
                foreach ( $section['links'] as $link ) {
                    $s['links'][] = array(
                        'id'       => sanitize_key( $link['id'] ?? 'lnk_' . wp_generate_uuid4() ),
                        'platform' => sanitize_key( $link['platform'] ?? 'link' ),
                        'url'      => esc_url_raw( $link['url'] ?? '' ),
                        'label'    => sanitize_text_field( $link['label'] ?? '' ),
                        'active'   => ! empty( $link['active'] ),
                    );
                }
            }
            $clean[] = $s;
        }
        return $clean;
    }

    /**
     * Generate a simple unique ID.
     */
    public static function uid( $prefix = 'kln' ) {
        return $prefix . '_' . substr( md5( uniqid( $prefix, true ) ), 0, 8 );
    }
}
